import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';

import { OpponentStatsParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/OpponentStatsParser';

export class OpponentStatsEvent extends MessageEvent implements IMessageEvent {
    constructor(callBack: Function) {
        super(callBack, OpponentStatsParser);
    }

    public getParser(): OpponentStatsParser {
        return this.parser as OpponentStatsParser;
    }
}
